class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> res;
        backtrack(res, num, 0);
        return res.size() >= 3 ? res : vector<int>();
    }
private:
    bool backtrack(vector<int>& res, string num, int start) {
        if (start == num.size() && res.size() >= 3) return true;
        for (int i = start; i < num.size(); ++i) {
            string cur = num.substr(start, i - start + 1);
            if (cur.size() > 1 && cur[0] == '0') break;
            long long val = stoll(cur);
            if (val > INT_MAX) break;
            if (res.size() >= 2 && val != res[res.size() - 1] + res[res.size() - 2]) continue;
            res.push_back(val);
            if (backtrack(res, num, i + 1)) return true;
            res.pop_back();
        }
        return false;
    }
};
